create extension if not exists pgcrypto;
create type shiplog_plan as enum ('free', 'starter', 'pro');
create type shiplog_entry_status as enum ('draft', 'scheduled', 'published');
create type shiplog_entry_type as enum ('feature', 'improvement', 'fix', 'security', 'announcement');
create type shiplog_cta_type as enum ('take_me_there', 'start_tour', 'watch_video', 'try_now');

create table orgs (id uuid primary key default gen_random_uuid(), name text not null, slug text unique not null, is_hosted boolean not null default false, plan shiplog_plan not null default 'free', created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table projects (id uuid primary key default gen_random_uuid(), org_id uuid not null references orgs(id) on delete cascade, name text not null, slug text unique not null, logo_url text, brand_color text not null default '#2563eb', theme jsonb not null default '{}', widget_settings jsonb not null default '{}', tone_settings jsonb not null default '{}', custom_domain text, created_at timestamptz not null default now());
create table entries (id uuid primary key default gen_random_uuid(), project_id uuid not null references projects(id) on delete cascade, title text not null, slug text not null, summary text not null, content text not null, type shiplog_entry_type not null default 'feature', categories text[] not null default '{}', status shiplog_entry_status not null default 'draft', source_metadata jsonb not null default '{}', cta_type shiplog_cta_type not null default 'take_me_there', cta_label text, cta_url text, media_attachments jsonb not null default '[]', scheduled_at timestamptz, published_at timestamptz, created_at timestamptz not null default now(), updated_at timestamptz not null default now(), unique(project_id, slug));
create table targeting_rules (id uuid primary key default gen_random_uuid(), entry_id uuid not null references entries(id) on delete cascade, rule jsonb not null, frequency_cap jsonb not null default '{}', created_at timestamptz not null default now());
create table segments (id uuid primary key default gen_random_uuid(), project_id uuid not null references projects(id) on delete cascade, name text not null, rule jsonb not null, created_at timestamptz not null default now());
create table widget_events (id uuid primary key default gen_random_uuid(), project_id uuid not null references projects(id) on delete cascade, entry_id uuid references entries(id) on delete set null, visitor_id text not null, user_id text, event text not null, page_url text, payload jsonb not null default '{}', created_at timestamptz not null default now());
create table subscriber_preferences (id uuid primary key default gen_random_uuid(), project_id uuid not null references projects(id) on delete cascade, email text not null, status text not null default 'subscribed', cadence text not null default 'all', categories text[] not null default '{}', created_at timestamptz not null default now(), updated_at timestamptz not null default now(), unique(project_id, email));
create table digests (id uuid primary key default gen_random_uuid(), project_id uuid not null references projects(id) on delete cascade, cadence text not null, subject text not null, intro text, entry_ids uuid[] not null default '{}', status text not null default 'draft', sent_at timestamptz, created_at timestamptz not null default now());
create table integrations (id uuid primary key default gen_random_uuid(), project_id uuid not null references projects(id) on delete cascade, provider text not null, status text not null default 'mock', config jsonb not null default '{}', created_at timestamptz not null default now(), unique(project_id, provider));
create table adoption_flows (id uuid primary key default gen_random_uuid(), entry_id uuid not null references entries(id) on delete cascade, name text not null, steps jsonb not null default '[]', follow_up_delay_hours integer not null default 72, created_at timestamptz not null default now());
create table adoption_events (id uuid primary key default gen_random_uuid(), entry_id uuid references entries(id) on delete set null, project_id uuid not null references projects(id) on delete cascade, visitor_id text not null, account_id text, event text not null, payload jsonb not null default '{}', created_at timestamptz not null default now());
create table usage_events (id uuid primary key default gen_random_uuid(), org_id uuid not null references orgs(id) on delete cascade, project_id uuid references projects(id) on delete set null, metric text not null, quantity integer not null default 1, created_at timestamptz not null default now());
create table encrypted_provider_key_config (id uuid primary key default gen_random_uuid(), org_id uuid not null references orgs(id) on delete cascade, provider text not null, encrypted_key text not null, key_hint text, created_at timestamptz not null default now(), updated_at timestamptz not null default now(), unique(org_id, provider));
create index widget_events_project_created_idx on widget_events(project_id, created_at desc);
create index entries_project_status_idx on entries(project_id, status, published_at desc);
create index adoption_events_entry_idx on adoption_events(entry_id, created_at desc);
